const advisorId = variables['f105371e-086b-4634-894a-5978cd09f35a'];

if (!advisorId) {
  alert('Chyba: Advisor ID nenalezeno');
  return;
}

try {
  console.log('🚀 Spouštím sync pro advisor:', advisorId);
  
  // DŮLEŽITÉ: mode: 'no-cors' NEBO vytvořit nový Request objekt
  const response = await fetch(
    'https://fzkliiqpeffdxnoykdsl.supabase.co/functions/v1/google-tasks-sync',
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        // NEPOSÍLEJ Authorization header
      },
      body: JSON.stringify({
        advisor_id: advisorId,
        direction: 'both'
      }),
      // DŮLEŽITÉ: Zakázat credentials (vypne Authorization)
      credentials: 'omit'
    }
  );
  
  console.log('📥 Response status:', response.status);
  
  const result = await response.json();
  console.log('📦 Result:', result);
  
  if (result.success) {
    console.log('✅ Sync úspěšná!', result.stats);
    alert(`Synchronizace dokončena!\n\nZ Google: ${result.stats.google_to_db.created} nových, ${result.stats.google_to_db.updated} upravených\nDo Google: ${result.stats.db_to_google.created} nových, ${result.stats.db_to_google.updated} upravených`);
    return result;
  } else {
    console.error('❌ Sync selhala:', result);
    alert('Chyba při synchronizaci: ' + (result.error || JSON.stringify(result)));
    return null;
  }
} catch (error) {
  console.error('❌ Complete error:', error);
  alert('Chyba sítě: ' + (error.message || error.toString()));
  return null;
}

